using sv_e16b6579d3ed46e7b162061acdcb93f0.Models;

namespace sv_e16b6579d3ed46e7b162061acdcb93f0.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.95m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 12.50m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Hub", Quantity = 45, UnitPrice = 49.99m, Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 60, UnitPrice = 89.00m, Category = "Clothing" },
        new Product { Id = 6, Name = "Notebook & Pen Set", Quantity = 200, UnitPrice = 7.25m, Category = "Other" },
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var snapshot = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category,
            }).ToList();

            return Task.FromResult(snapshot);
        }
    }

    public Task UpdateAsync(Product updated)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == updated.Id)
                ?? throw new InvalidOperationException($"Product with Id {updated.Id} not found.");

            existing.Name = updated.Name;
            existing.Quantity = updated.Quantity;
            existing.UnitPrice = updated.UnitPrice;
            existing.Category = updated.Category;
        }

        return Task.CompletedTask;
    }
}

