+    <p><em>Loading...</em></p>
+}
+else if (products.Count == 0)
+{
+    <p>No products found.</p>
+}
+else
+{
+    @if (saveError is not null)
+    {
+        <div class="alert alert-danger" role="alert">@saveError</div>
+    }
+
+    <table class="table table-striped">
+        <thead>
+            <tr>
+                <th>Name</th>
+                <th>Quantity</th>
+                <th>Unit Price</th>
+                <th>Category</th>
+                <th>Actions</th>
+            </tr>
+        </thead>
+        <tbody>
+            @foreach (var product in products)
+            {
+                <tr @key="product.Id">
+                    @if (editingProductId == product.Id)
+                    {
+                        <td>
+                            <input class="form-control" @bind="editName" />
+                            @if (validationErrors.TryGetValue("Name", out var nameErr))
+                            {
+                                <div class="text-danger">@nameErr</div>
+                            }
+                        </td>
+                        <td>
+                            <input type="number" class="form-control" @bind="editQuantity" />
+                            @if (validationErrors.TryGetValue("Quantity", out var qtyErr))
+                            {
+                                <div class="text-danger">@qtyErr</div>
+                            }
+                        </td>
+                        <td>
+                            <input type="number" step="0.01" class="form-control" @bind="editUnitPrice" />
+                            @if (validationErrors.TryGetValue("UnitPrice", out var priceErr))
+                            {
+                                <div class="text-danger">@priceErr</div>
+                            }
+                        </td>
+                        <td>
+                            <select class="form-select" @bind="editCategory">
+                                <option value="">-- Select --</option>
+                                @foreach (var cat in Categories)
+                                {
+                                    <option value="@cat">@cat</option>
+                                }
+                            </select>
+                            @if (validationErrors.TryGetValue("Category", out var catErr))
+                            {
+                                <div class="text-danger">@catErr</div>
+                            }
+                        </td>
+                        <td>
+                            <button class="btn btn-success btn-sm me-1" @onclick="SaveAsync" disabled="@isSaving">Save</button>
+                            <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@isSaving">Cancel</button>
+                        </td>
+                    }
+                    else
+                    {
+                        <td>@product.Name</td>
+                        <td>@product.Quantity</td>
+                        <td>@product.UnitPrice.ToString("C")</td>
+                        <td>@product.Category</td>
+                        <td>
+                            <button class="btn btn-primary btn-sm" @onclick="() => StartEdit(product)" disabled="@(editingProductId is not null)">Edit</button>
+                        </td>
+                    }
+                </tr>
+            }
+        </tbody>
+    </table>
+}
+
+@code {
+    private static readonly string[] Categories = ["Electronics", "Clothing", "Food", "Other"];
+
+    private List<Product>? products;
+    private int? editingProductId;
+    private bool isSaving;
+    private string? saveError;
+
+    private string editName = string.Empty;
+    private int editQuantity;
+    private decimal editUnitPrice;
+    private string editCategory = string.Empty;
+
+    private Dictionary<string, string> validationErrors = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        products = await InventoryService.GetAllAsync();
+    }
+
+    private void StartEdit(Product product)
+    {
+        editingProductId = product.Id;
+        editName = product.Name;
+        editQuantity = product.Quantity;
+        editUnitPrice = product.UnitPrice;
+        editCategory = product.Category;
+        validationErrors.Clear();
+        saveError = null;
+    }
+
+    private void Cancel()
+    {
+        editingProductId = null;
+        validationErrors.Clear();
+        saveError = null;
+    }
+
+    private bool Validate()
+    {
+        validationErrors.Clear();
+
+        if (string.IsNullOrWhiteSpace(editName))
+        {
+            validationErrors["Name"] = "Name is required.";
+        }
+
+        if (editQuantity < 0 || editQuantity > 9999)
+        {
+            validationErrors["Quantity"] = "Quantity must be between 0 and 9999.";
+        }
+
+        if (editUnitPrice <= 0)
+        {
+            validationErrors["UnitPrice"] = "Unit Price must be greater than 0.";
+        }
+
+        if (string.IsNullOrWhiteSpace(editCategory))
+        {
+            validationErrors["Category"] = "Category is required.";
+        }
+
+        return validationErrors.Count == 0;
+    }
+
+    private async Task SaveAsync()
+    {
+        if (!Validate())
+        {
+            return;
+        }
+
+        isSaving = true;
+        saveError = null;
+
+        try
+        {
+            var updated = new Product
+            {
+                Id = editingProductId!.Value,
+                Name = editName.Trim(),
+                Quantity = editQuantity,
+                UnitPrice = editUnitPrice,
+                Category = editCategory,
+            };
+
+            await InventoryService.UpdateAsync(updated);
+            products = await InventoryService.GetAllAsync();
+            editingProductId = null;
+        }
+        catch (Exception ex)
+        {
+            saveError = $"Failed to save: {ex.Message}";
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+}
+

